class Solution(object):
    def maxScore(self, nums, x):
        # dp[p] = max score achievable ending at any position with parity p
        dp = [float('-inf'), float('-inf')]
        dp[nums[0] % 2] = nums[0]

        for i in range(1, len(nums)):
            p = nums[i] % 2
            # arrive from same parity (no penalty) or different parity (subtract x)
            best = max(dp[p], dp[1 - p] - x) + nums[i]
            dp[p] = max(dp[p], best)

        return max(dp)
